-- Entity database dump (auto-generated)
PRAGMA foreign_keys = OFF;

CREATE TABLE IF NOT EXISTS _meta (
            migration_id INTEGER PRIMARY KEY,
            filename     TEXT NOT NULL,
            applied_at   TEXT NOT NULL DEFAULT (datetime('now'))
        );

CREATE TABLE IF NOT EXISTS audit_log (id INTEGER PRIMARY KEY, action TEXT, table_name TEXT, row_id INTEGER, ts TEXT DEFAULT (datetime('now')));

CREATE TABLE IF NOT EXISTS batch_test (id INTEGER PRIMARY KEY, name TEXT, score REAL);

CREATE TABLE IF NOT EXISTS blobs_test (id INTEGER PRIMARY KEY, data BLOB);

CREATE TABLE IF NOT EXISTS companies (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    country TEXT,
    founded INTEGER,
    revenue REAL
, ceo TEXT);

CREATE TABLE IF NOT EXISTS ctas_test(id INT,name TEXT,country TEXT);

CREATE TABLE IF NOT EXISTS people (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    role TEXT,
    company_id INTEGER REFERENCES companies(id)
);

CREATE TABLE IF NOT EXISTS profitable_companies(
  id INT,
  name TEXT,
  country TEXT,
  revenue REAL
);

CREATE TABLE IF NOT EXISTS recovery_test (
    id INTEGER PRIMARY KEY,
    tricky_text TEXT,
    num REAL,
    blob_col BLOB
);

CREATE TABLE IF NOT EXISTS tags (name TEXT PRIMARY KEY, color TEXT) WITHOUT ROWID;

CREATE TABLE IF NOT EXISTS test_crud (id INTEGER PRIMARY KEY, name TEXT NOT NULL, score REAL, active INTEGER DEFAULT 1);

CREATE TABLE IF NOT EXISTS test_mixed (id INTEGER PRIMARY KEY, val TEXT);

CREATE TABLE IF NOT EXISTS trigger_log (id INTEGER PRIMARY KEY, event TEXT, ts TEXT DEFAULT (datetime('now')));

CREATE TABLE IF NOT EXISTS type_edge (id INTEGER PRIMARY KEY, int_col INTEGER, text_col TEXT, real_col REAL, blob_col BLOB);

CREATE TABLE IF NOT EXISTS us_companies_snapshot(
  id INT,
  name TEXT,
  revenue REAL
);

CREATE TRIGGER trg_company_delete BEFORE DELETE ON companies
BEGIN
  INSERT INTO trigger_log (event) VALUES ('DELETE company: ' || OLD.name);
END;

CREATE TRIGGER trg_company_insert AFTER INSERT ON companies
BEGIN
  INSERT INTO trigger_log (event) VALUES ('INSERT company: ' || NEW.name);
END;

CREATE TRIGGER trg_company_update AFTER UPDATE ON companies
BEGIN
  INSERT INTO trigger_log (event) VALUES ('UPDATE company: ' || OLD.name || ' -> ' || NEW.name);
END;

CREATE VIEW company_summary AS
SELECT c.name, c.country, COUNT(p.id) AS employee_count
FROM companies c
LEFT JOIN people p ON p.company_id = c.id
GROUP BY c.id, c.name, c.country;

